## JavaScript (ES6)

```js
/**
 * Returns true if `str` is a palindrome.
 * Ignores case and all non‑alphanumeric characters.
 *
 * @param {string} str
 * @returns {boolean}
 */
function isPalindrome(str) {
    // Remove everything that's not a letter or digit, then lower‑case it
    const cleaned = str.replace(/[^A-Za-z0-9]/g, '').toLowerCase();
    // Compare with the reversed version
    const reversed = cleaned.split('').reverse().join('');
    return cleaned === reversed;
}

// ---- demo --------------------------------------------------------
['Racecar',
 'A man, a plan, a canal: Panama',
 'No lemon, no melon',
 'Hello, World!'].forEach(s => {
    console.log(`"${s}" -> ${isPalindrome(s)}`);
});
```

